+#[inline]
+fn normalized_nprocs(name: c_int) -> c_int {
+    let value = unsafe { sysconf(name) };
+    if value <= 0 || value > c_int::MAX as libc::c_long {
+        1
+    } else {
+        value as c_int
+    }
+}
